 1	import type { FC } from 'react';
 2	import { useForkliftTranslation } from 'src/utils/i18n';
 3	
 4	import { Button, ButtonVariant, DataList } from '@patternfly/react-core';
 5	import { PlusCircleIcon } from '@patternfly/react-icons';
 6	
 7	import type { Mapping, MappingSource } from '../types';
 8	
 9	import { MappingListItem } from './MappingListItem';
10	
11	import '../ProvidersCreateVmMigration.style.css';
12	
13	type MappingListProps = {
14	  mappings?: Mapping[];
15	  sources: MappingSource[];
16	  availableDestinations: string[];
17	  replaceMapping: (val: { current: Mapping; next: Mapping }) => void;
18	  deleteMapping: (mapping: Mapping) => void;
19	  addMapping: () => void;
20	  usedSourcesLabel: string;
21	  generalSourcesLabel: string;
22	  noSourcesLabel: string;
23	  isDisabled: boolean;
24	};
25	
26	export const MappingList: FC<MappingListProps> = ({
27	  addMapping,
28	  availableDestinations,
29	  deleteMapping,
30	  generalSourcesLabel,
31	  isDisabled,
32	  mappings,
33	  noSourcesLabel,
34	  replaceMapping,
35	  sources,
36	  usedSourcesLabel,
37	}) => {
38	  const { t } = useForkliftTranslation();
39	  const usedSources = sources.filter(({ usedBySelectedVms }) => usedBySelectedVms);
40	  const generalSources = sources.filter(({ usedBySelectedVms }) => !usedBySelectedVms);
41	  const allMapped = sources.every(({ isMapped }) => isMapped);
42	  return (
43	    <>
44	      <DataList isCompact aria-label="">
45	        {mappings?.map(({ destination, source }, index) => (
46	          <MappingListItem
47	            source={source}
48	            destination={destination}
49	            destinations={availableDestinations}
50	            generalSources={generalSources}
51	            usedSources={usedSources}
52	            replaceMapping={replaceMapping}
53	            deleteMapping={deleteMapping}
54	            index={index}
55	            key={`${source}-${destination}`}
56	            generalSourcesLabel={generalSourcesLabel}
57	            usedSourcesLabel={usedSourcesLabel}
58	            noSourcesLabel={noSourcesLabel}
59	            isDisabled={isDisabled}
60	          />
61	        ))}
62	      </DataList>
63	      <Button
64	        onClick={addMapping}
65	        type="button"
66	        variant={ButtonVariant.link}
67	        isDisabled={allMapped || isDisabled}
68	        icon={<PlusCircleIcon />}
69	      >
70	        {t('Add mapping')}
71	      </Button>
72	    </>
73	  );
74	};

